/* MODUS FX — cosméticos vetoriais (carregado uma vez, cacheado) */
window.MODUSFX=(function(){
const SVG={"fogo":"<svg viewBox=\"0 0 196 191\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"196\" height=\"191\" href=\"data:image/png;base64,\"/></svg>","gelo":"<svg viewBox=\"0 0 199 197\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"199\" height=\"197\" href=\"data:image/png;base64,\"/></svg>","lava":"<svg viewBox=\"0 0 190 190\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"190\" height=\"190\" href=\"data:image/png;base64,\"/></svg>","obsidiana":"<svg viewBox=\"0 0 202 197\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"202\" height=\"197\" href=\"data:image/png;base64,\"/></svg>","solar":"<svg viewBox=\"0 0 200 191\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"200\" height=\"191\" href=\"data:image/png;base64,\"/></svg>","arcano":"<svg viewBox=\"0 0 192 191\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"192\" height=\"191\" href=\"data:image/png;base64,\"/></svg>","arcoiris":"<svg viewBox=\"0 0 199 190\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"199\" height=\"190\" href=\"data:image/png;base64,\"/></svg>","brasa":"<svg viewBox=\"0 0 192 190\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"192\" height=\"190\" href=\"data:image/png;base64,\"/></svg>","constelacao":"<svg viewBox=\"0 0 190 189\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"190\" height=\"189\" href=\"data:image/png;base64,\"/></svg>","espirito":"<svg viewBox=\"0 0 209 196\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"209\" height=\"196\" href=\"data:image/png;base64,\"/></svg>","eclipse":"<svg viewBox=\"0 0 138 147\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"138\" height=\"147\" href=\"data:image/png;base64,\"/></svg>","louros_ouro":"<svg viewBox=\"0 0 198 191\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"198\" height=\"191\" href=\"data:image/png;base64,\"/></svg>","louros":"<svg viewBox=\"0 0 185 171\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"185\" height=\"171\" href=\"data:image/png;base64,\"/></svg>","videira":"<svg viewBox=\"0 0 197 195\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"197\" height=\"195\" href=\"data:image/png;base64,\"/></svg>","bussola":"<svg viewBox=\"0 0 156 177\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"156\" height=\"177\" href=\"data:image/png;base64,\"/></svg>","cajado":"<svg viewBox=\"0 0 153 156\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"153\" height=\"156\" href=\"data:image/png;base64,\"/></svg>","ampulheta":"<svg viewBox=\"0 0 98 167\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"98\" height=\"167\" href=\"data:image/png;base64,\"/></svg>","diamante":"<svg viewBox=\"0 0 158 132\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"158\" height=\"132\" href=\"data:image/png;base64,\"/></svg>","elmo":"<svg viewBox=\"0 0 116 168\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"116\" height=\"168\" href=\"data:image/png;base64,\"/></svg>","leao":"<svg viewBox=\"0 0 157 178\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"157\" height=\"178\" href=\"data:image/png;base64,\"/></svg>","estrela":"<svg viewBox=\"0 0 138 137\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"138\" height=\"137\" href=\"data:image/png;base64,\"/></svg>","lira":"<svg viewBox=\"0 0 148 167\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"148\" height=\"167\" href=\"data:image/png;base64,\"/></svg>","torre":"<svg viewBox=\"0 0 108 178\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"108\" height=\"178\" href=\"data:image/png;base64,\"/></svg>","olho":"<svg viewBox=\"0 0 150 163\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"150\" height=\"163\" href=\"data:image/png;base64,\"/></svg>","sol":"<svg viewBox=\"0 0 152 152\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"152\" height=\"152\" href=\"data:image/png;base64,\"/></svg>","lua":"<svg viewBox=\"0 0 141 152\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"141\" height=\"152\" href=\"data:image/png;base64,\"/></svg>","livro_arvore":"<svg viewBox=\"0 0 145 168\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"145\" height=\"168\" href=\"data:image/png;base64,\"/></svg>","gema_azul":"<svg viewBox=\"0 0 152 146\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"152\" height=\"146\" href=\"data:image/png;base64,\"/></svg>","gema_verde":"<svg viewBox=\"0 0 142 146\" xmlns=\"http://www.w3.org/2000/svg\"><image width=\"142\" height=\"146\" href=\"data:image/png;base64,\"/></svg>"};

/* devolve o markup de um cosmético como camada sobre a foto.
   key = chave do SVG; fx = movimento (girL/girM/pulsa/cintila); cls extra */
function ring(key,fx){
  const svg=SVG[key]; if(!svg) return "";
  return '<span class="fxring '+(fx||"")+'">'+svg+'</span>';
}
function badge(key){
  const svg=SVG[key]; if(!svg) return "";
  return '<span class="fxbadge">'+svg+'</span>';
}
function icon(key,cls){
  const svg=SVG[key]; if(!svg) return "";
  return '<span class="'+(cls||"fxicon")+'">'+svg+'</span>';
}
function has(key){ return !!SVG[key]; }
return { SVG, ring, badge, icon, has };
})();
